const h3 = require('h3-js');

// Convert lat/lng to an H3 cell at resolution 9 (adjust resolution per city density)
const lat = 37.775938728915946;
const lng = -122.41795063018799;
const resolution = 9;
const cell = h3.geoToH3(lat, lng, resolution);
console.log('H3 cell:', cell);

// Get neighboring cells (k ring = 1 -> immediate neighbors)
const neighbors = h3.kRing(cell, 1);
console.log('Neighbors count:', neighbors.length);
